#!/usr/bin/env bash
# lora-ipadapter-decay-risk-medium.sh — 角色/风格一致性（LoRA 训练 + IPAdapter/参考图）(Decay risk: medium) last_updated: 2026-06-22 SOP walkthrough for AIGC 创作工作流.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="AIGC 创作工作流"
WORKFLOW="角色/风格一致性（LoRA 训练 + IPAdapter/参考图）(Decay risk: medium) last_updated: 2026-06-22"

usage() {
  cat <<EOF
lora-ipadapter-decay-risk-medium.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./lora-ipadapter-decay-risk-medium.sh             # interactive
  ./lora-ipadapter-decay-risk-medium.sh --dry-run
  ./lora-ipadapter-decay-risk-medium.sh --json
  ./lora-ipadapter-decay-risk-medium.sh --explain
  ./lora-ipadapter-decay-risk-medium.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "角色/风格一致性（LoRA 训练 + IPAdapter/参考图）(Decay risk: medium) last_updated: 2026-06-22" 工作流。

一句话: 让同一角色/画风跨多张图稳定出现 —— 两条路线：免训练参考（IPAdapter/InstantID/Omni Reference）或训练 LoRA（打标→训练→应用）。从「每张脸都不一样」到「跨图同一角色」。

入门 SOP 共 5 步, 失败模式自检 3 项。

相关心智模型:
  • 可控性 ⇄ 抽卡随机（slot machine）的第一性张力: 扩散模型本质是「抽卡机」（Bilawal Sidhu 直接命名 slot machine nature），同 prompt 多跑挑可用——生成式视觉创作的每个决策都在「可控性/工程化复现 ⇄ 随机性/
  • 模型是地板，审美与判断是天花板: 同样的模型与参数，产出天差地别取决于人的审美判断、概念、构图、镜头语言与「在哪一步停」的判断；模型决定下限（地板），人的审美与工程判断决定上限（天花板），「换个更大的底模就行」是外行幻觉。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**备数据集**：收集 20-60+ 张目标角色/风格清晰图（多角度、多光照），统一裁到 1024。(evidence: [T03-S009])"
  "**打标（captioning）**：用 BLIP/WD14/Joy Caption 自动打标，**手动复核**加触发词、删无关背景描述。(evidence: [T03-S009])"
  "**设训练参数**：选工具（Flux/Flux.2/Qwen 用 ai-toolkit，SDXL/Flux 也可 Kohya）；Flux LoRA 学习率 1e-4（出问题降 5e-5）、cosine scheduler、约 1500-2500 step。(evidence: [T03-S009, T03-S010])"
  "**训练**：跑训练，定期看样本图判断是否过/欠拟合。"
  "**应用**：在 ComfyUI/Forge 用 Load LoRA 节点挂上，调 LoRA 权重（0.6-1.0），配触发词出图。"
)
declare -a FAILURE_MODES=(
  "**数据集差就开练**：20 张同角度同光照图训出来只会复刻、换姿势崩 —— 先备 20-60 张多角度多光照图、手工打标加触发词，再训。"
  "**能免训练却硬训 LoRA**：单角色短期需求花半天训 LoRA，IPAdapter/InstantID 几分钟能搞定 —— 先问「这是长期 IP 还是一次性」，一次性走免训练。"
  "**底模代际错配**：SDXL LoRA 挂到 Flux 底模无效 —— 训练前确定目标底模，训对应代际 LoRA。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "lora-ipadapter-decay-risk-medium-walkthrough"
fi
